var isLoginPage = function (noiframes) {
  // This function checks if the target element contains any input fields of type password,
  // which is a common indicator of a login page. If such fields are found, it returns true,
  // otherwise it returns false.
  function hasLoginPage(target) {
    var passwords = target.querySelectorAll("input[type=password]");
    if (passwords.length > 0) {
      console.dir(passwords);
      return true;
    } else {
      return false;
    }
  }

  // This function retrieves all iframes from the given document and returns an array of those
  // iframes whose contentDocument is accessible. This is useful for checking if the iframes
  // contain any login forms.
  function getLocalIframes(doc) {
    var allIframes = doc.getElementsByTagName("iframe"),
      localIframes = [];

    for (var i = 0; i < allIframes.length; i++) {
      try {
        if (allIframes[i].contentDocument) {
          localIframes.push(allIframes[i]);
        }
      } catch (e) {}
    }
    return localIframes;
  }

  // If the target is not a login page, it will check all accessible iframes within the target.
  function executeInIframes(iframes, hasLoginPage, callback) {
    var iframeDoc,
      numFrames = iframes.length,
      falseReturns = 0;

    if (!numFrames) {
      callback(false);
    }

    function _checkIframeLogin(documentBody) {
      try {
        if (hasLoginPage(documentBody)) {
          callback(true);
        } else {
          if (++falseReturns === numFrames) {
            callback(false); //in case all iframes were falsy
          }
        }
      } catch (e) {
        if (++falseReturns === numFrames) {
          callback(false); //in case all iframes were falsy
        }
      }
    }

    for (var i = 0; i < numFrames; i++) {
      iframeDoc = iframes[i].contentDocument;

      if (iframeDoc && iframeDoc.readyState === "complete") {
        _checkIframeLogin(iframeDoc.body);
      } else {
        iframes[i].addEventListener("load", function () {
          _checkIframeLogin(this.contentDocument.body);
        });
      }
    }
  }

  // If the target is not a login page, it will check all accessible iframes within the target.
  // If noiframes is set to true, the function will not check iframes.
  // The callback function is called with true if a login page is found, otherwise false.
  function isLoginPage(target, callback) {
    if (hasLoginPage(target)) {
      callback(true);
    } else {
      if (noiframes) {
        callback(false);
      } else {
        executeInIframes(getLocalIframes(target), hasLoginPage, callback);
      }
    }
  }

  return isLoginPage;
};

export { isLoginPage };
