import { toBackground } from "../messages/index.js";
import portalPageClassifier from "../global/oneloginApiServer/portalPageClassifier.js";
import { isLoginPage } from "../trainer/utils/isLoginPage.js";
import { waitForReadyContent } from "../trainer/utils/waitForReadyContent.js";
import { showAddAppButton } from "../trainer/trainerDialog.js";

var currentLocation = window.location.toString();

function isTopWindow() {
  return window.top === window;
}

function checkAndShowAddAppButton() {
  toBackground("onelogin.getUserSettings", function (res) {
    if (res && res.status == "SUCCESS") {
      let userSettings = res.data;
      if (userSettings && userSettings.tab_enabled) {
        toBackground("onelogin.getServerInfo", function (serverInfoRes) {
          toBackground(
            "onelogin.getTrainerDialogInfo",
            {
              currentLocation,
              serverUrl: serverInfoRes.data.serverUrl,
            },
            function (trainerDialogResponse) {
              if (trainerDialogResponse && trainerDialogResponse.status == "SUCCESS") {
                showAddAppButton(
                  currentLocation,
                  serverInfoRes.data.serverUrl,
                  trainerDialogResponse.data,
                  toBackground
                );
              } else {
                console.log("ol_extension: error fetching trainer dialog data: ", res.data);
              }
            }
          );
        });
      } else {
        console.log("ol_extension: addApp button toolbar disabled by user setting (tab_enabled)");
      }
    } else {
      console.log("ol_extension: error fetching user settings from background: ", res.data);
    }
  });
}

if (isTopWindow()) {
  /**
   * If the current page is not a onelogin portal page
   */
  if (!portalPageClassifier.isOneloginPortal(currentLocation)) {
    // send a message to background to get the extension url
    toBackground("onelogin.currentContext", function (contextResponse) {
      let extensionUrl = contextResponse.data.extensionUrl;
      // If the script is executing in extensions context
      if (currentLocation.includes(extensionUrl)) {
        return;
      }
      // send a message to background to check if login process is active
      toBackground("onelogin.isLoginProcessActive", function (response) {
        if (response && response.status == "SUCCESS") {
          waitForReadyContent()
            .then(() => {
              // isLoginPage() returns a function that takes two params
              // a target page to check and a callback to report results
              isLoginPage()(document.body, function (isPageLoginPage) {
                if (isPageLoginPage) checkAndShowAddAppButton();
              });
            })
            .catch((err) => {
              console.log("ol_extension: error checking isLoginPage: ", err);
            });
        }
      });
    });
  }
}
