/*
  When user lands on login page that is not in his list of apps, the extension renders "Add app"button in left top corner.
  This provides the user a possibility to create new connector based on clicking on username/passoword fields and submit button. 
 */

var buttonShown = false;

function createElement(htmlStr) {
  var container = document.createElement("div");
  container.style.position = "fixed";
  container.style.top = "0px";
  container.style.left = "0px";
  container.style["z-index"] = "999999";
  container.innerHTML = htmlStr;
  return container;
}

function stopPropagation(event) {
  event = event || window.event;
  if (event.stopPropagation) {
    event.stopPropagation();
  } else {
    event.cancelBubble = true;
  }
}

function showAddAppButton(currentUrl, serverUrl, trainerDialogData, toBackground) {
  if (buttonShown) {
    //isLoginPage callback can be called more time for each iframe - TODO: move to executeInIframes
    return;
  }
  buttonShown = true;

  var doc = window.document;
  if (doc.cookie.match("ol_close_add_app=true")) return;

  var closeImage64 =
    "background-image: url('data:image/png;base64,');";
  var closeAddAppButton =
    '<div style="display:inline-block">' +
    '<div id="ol_close_add_app"style="' +
    closeImage64 +
    "cursor:pointer;"+
    "opacity:0.5;"+
    "visibility:hidden;"+
    "width:20px;"+
    "height:20px;"+
    'z-index:999999">' +
    "</div>"+
    '<div style="' +
    "width: 20px;"+
    'height: 30px;">' +
    "</div>"+
    "</div>";

  var addAppImage64 =
    "background-image:url('data:image/png;base64,');";
  var trainAddAppButton =
    '<div id="train_add_app_tab"title="OneLogin Actions"style="' +
    addAppImage64 +
    "cursor:pointer;"+
    "display:inline-block;"+
    "width:50px;"+
    "height:50px;"+
    'z-index:999999">' +
    "</div>";

  var tabHtml = trainAddAppButton + closeAddAppButton;

  var addAppContainer = createElement(tabHtml);

  function showTrainerOrRedirect(event) {
    stopPropagation(event);
    if (
      typeof trainerDialogData === "string"&&
      trainerDialogData.includes("function perform_login(doc) {")
    ) {
      toBackground("onelogin.injectTrainerDialogScript", { serverUrl });
    } else if (
      typeof trainerDialogData === "string"&&
      trainerDialogData.includes("document.location.href =")
    ) {
      var location = trainerDialogData.substring(
        trainerDialogData.indexOf("'") + 1,
        trainerDialogData.lastIndexOf("'")
      );
      window.location.href = location;
    } else {
      /**
       * if not known response, redirect to onelogin login page
       */
      window.location.href = `${serverUrl}/login`;
    }
  }

  addAppContainer.firstChild.onclick = showTrainerOrRedirect;

  doc.body.insertBefore(addAppContainer, doc.body.childNodes[0]);

  var closeAddApp = doc.getElementById("ol_close_add_app");
  var closeAddAppListener = function (event) {
    stopPropagation(event);
    this.parentElement.parentElement.style.display = "none";
    doc.cookie = "ol_close_add_app=true";
  };
  var toggleCloseButtonOpacity = function () {
    closeAddApp.style.opacity = closeAddApp.style.opacity == "0.5"? "1": "0.5";
  };
  closeAddApp.onclick = closeAddAppListener;
  closeAddApp.addEventListener("mouseover", toggleCloseButtonOpacity, true);
  closeAddApp.addEventListener("mouseleave", toggleCloseButtonOpacity, true);

  var trainAddApp = doc.getElementById("train_add_app_tab");
  var toggleCloseButtonVisibility = function () {
    closeAddApp.style.visibility = "visible";
  };
  trainAddApp.parentElement.addEventListener("mouseover", toggleCloseButtonVisibility, true);
}

export { showAddAppButton };
