function setExtTimeout(callback, ms) {
  // can be utilised by safari
  return setTimeout(function () {
    callback();
    console.log("CALLING");
  }, ms);
}

function clearExtTimeout(id) {
  clearTimeout(id);
}

function setTimeoutPromisified(t, val) {
  return new Promise((resolve) => setTimeout(resolve, t, val));
}

export { setExtTimeout, clearExtTimeout, setTimeoutPromisified };
