import { setTimeoutPromisified } from "../../global/timeout.js";
import readyState from "./readyState.js";

async function waitForReadyContent() {
  async function checkReadyState() {
    try {
      if (readyState()) {
        await setTimeoutPromisified(0);
        return;
      } else {
        await setTimeoutPromisified(100);
        await checkReadyState();
      }
    } catch (e) {
      await setTimeoutPromisified(0);
      throw e;
    }
  }

  await checkReadyState();
}

export { waitForReadyContent };
